var PARTNERS_ACTIVE_TAB='inquiries';var PARTNERS_TIERS_CACHE=[];document.addEventListener('click',function(ev){var btn=ev.target.closest('.partners-subtab');if(!btn)return;var tab=btn.getAttribute('data-partners-tab');if(!tab||tab===PARTNERS_ACTIVE_TAB)return;PARTNERS_ACTIVE_TAB=tab;document.querySelectorAll('.partners-subtab').forEach(function(b){var on=b.getAttribute('data-partners-tab')===tab;b.style.background=on?'rgba(168,255,0,.12)':'transparent';b.style.color=on?'#A8FF00':'#888';b.style.borderColor=on?'rgba(168,255,0,.3)':'#2a2a2a';b.classList.toggle('active',on);});document.querySelectorAll('.partners-pane').forEach(function(p){p.style.display=(p.id==='partners-pane-'+tab)?'':'none';});if(tab==='inquiries')loadPartnerInquiries();else if(tab==='tiers')loadPartnerTiers();else if(tab==='directory')loadPartnerDirectory();else if(tab==='offers')loadPartnerOffers();else if(tab==='redemptions')loadPartnerRedemptions();});function loadPartnerInquiries(){var status=(document.getElementById('partnersInquiryFilter')||{}).value||'';var url=ATP_API+'/partners/admin/inquiries'+(status?'?status='+encodeURIComponent(status):'');fetch(url,{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){renderPartnerInquiries((data&&data.inquiries)||[]);}).catch(function(){document.getElementById('partnerInquiriesList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load inquiries.</div>';});}
function renderPartnerInquiries(list){var el=document.getElementById('partnerInquiriesList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center;font-size:13px">No inquiries yet. Once a brand submits the form on /partners, leads land here.</div>';var badge=document.getElementById('adminPartnersBadge');if(badge)badge.style.display='none';return;}
var newCount=list.filter(function(i){return i.status==='new';}).length;var badge=document.getElementById('adminPartnersBadge');if(badge){if(newCount>0){badge.textContent=newCount+' new';badge.style.display='';}else{badge.style.display='none';}}
var statusColors={new:{bg:'rgba(245,158,11,.15)',fg:'#fbbf24',border:'rgba(245,158,11,.4)'},contacted:{bg:'rgba(96,165,250,.15)',fg:'#93c5fd',border:'rgba(96,165,250,.4)'},qualified:{bg:'rgba(168,255,0,.15)',fg:'#A8FF00',border:'rgba(168,255,0,.4)'},won:{bg:'rgba(168,255,0,.3)',fg:'#C6FF55',border:'rgba(168,255,0,.6)'},lost:{bg:'rgba(239,68,68,.15)',fg:'#fca5a5',border:'rgba(239,68,68,.4)'},};el.innerHTML=list.map(function(i){var color=statusColors[i.status]||statusColors.new;var when=i.created_at?new Date(i.created_at).toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})+' · '+new Date(i.created_at).toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'}):'';var name=(i.contact_name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var email=(i.contact_email||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var company=(i.company||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var msg=(i.message||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/\n/g,'<br>');return'<div style="background:#0d0d0d;border:1px solid #222;border-left:3px solid '+color.border+';border-radius:10px;padding:18px;margin-bottom:10px">'+'<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:14px;margin-bottom:10px;flex-wrap:wrap">'+'<div>'+'<div style="font-size:15px;font-weight:700;color:#fff;margin-bottom:3px">'+name+
(company?' <span style="font-weight:500;color:#888;font-size:13px">· '+company+'</span>':'')+'</div>'+'<div style="font-size:12px;color:#888"><a href="mailto:'+email+'" style="color:#A8FF00">'+email+'</a>'+
(i.contact_phone?' · '+i.contact_phone:'')+'</div>'+'</div>'+'<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">'+'<span style="font-size:11px;color:#666">'+when+'</span>'+'<select onchange="updateInquiryStatus(\''+i.id+'\', this.value)" style="background:'+color.bg+';color:'+color.fg+';border:1px solid '+color.border+';border-radius:20px;padding:4px 10px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;cursor:pointer">'+
['new','contacted','qualified','won','lost'].map(function(s){return'<option value="'+s+'"'+(s===i.status?' selected':'')+'>'+s+'</option>';}).join('')+'</select>'+'</div>'+'</div>'+'<div style="display:flex;gap:14px;flex-wrap:wrap;font-size:12px;color:#aaa;margin-bottom:'+(msg?'12px':'0')+'">'+
(i.tier_name?'<span>📦 <strong style="color:#fff">'+i.tier_name+'</strong></span>':'')+
(i.brand_size?'<span>👥 '+i.brand_size+'</span>':'')+
(i.budget_band?'<span>💰 '+i.budget_band+'</span>':'')+'</div>'+
(msg?'<div style="font-size:13px;color:#ddd;line-height:1.6;padding:12px;background:#161616;border-radius:6px">'+msg+'</div>':'')+'</div>';}).join('');}
function updateInquiryStatus(id,status){fetch(ATP_API+'/partners/admin/inquiries/'+id,{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify({status:status}),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Status updated');loadPartnerInquiries();});}
function loadPartnerTiers(){fetch(ATP_API+'/partners/admin/tiers',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){PARTNERS_TIERS_CACHE=(data&&data.tiers)||[];renderPartnerTiers(PARTNERS_TIERS_CACHE);_populatePartnerDirTierSelect();});}
function renderPartnerTiers(list){var el=document.getElementById('partnerTiersList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center">No tiers yet. Run /api/auth/migrate-partners to seed the defaults, or add one above.</div>';return;}
el.innerHTML=list.map(function(t){var price=parseInt(t.monthly_price_cents,10)||0;var ccy=(t.currency||'aed').toUpperCase();var priceTxt=price===0?'Custom pricing':ccy+' '+(price/100).toLocaleString()+' / month';var perks=Array.isArray(t.perks)?t.perks:(typeof t.perks==='string'?(function(){try{return JSON.parse(t.perks);}catch(e){return[];}})():[]);var name=(t.name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var status=t.is_active?'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(168,255,0,.15);color:#A8FF00">Active</span>':'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(255,255,255,.06);color:#666">Off</span>';var featured=t.is_featured?'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(245,158,11,.18);color:#fbbf24;border:1px solid rgba(245,158,11,.4)">★ Featured</span>':'';return'<div style="background:#0d0d0d;border:1px solid #222;border-radius:10px;padding:18px;margin-bottom:10px">'+'<div style="display:flex;justify-content:space-between;gap:14px;margin-bottom:10px;flex-wrap:wrap">'+'<div>'+'<div style="display:flex;gap:8px;align-items:center;margin-bottom:4px">'+'<span style="font-size:15px;font-weight:700;color:#fff">'+name+'</span>'+
featured+status+'</div>'+'<div style="font-size:13px;color:#A8FF00;font-weight:600">'+priceTxt+'</div>'+
(t.tagline?'<div style="font-size:12px;color:#888;margin-top:4px">'+t.tagline.replace(/</g,'&lt;')+'</div>':'')+'</div>'+'<div style="display:flex;gap:6px;align-items:flex-start">'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px" data-atp-call="editPartnerTier" data-args=\'["'+t.id+'"]\'>Edit</button>'+'<button class="admin-btn admin-btn-danger" style="font-size:11px;padding:5px 10px" data-atp-call="deletePartnerTier" data-args=\'["'+t.id+'"]\'>Deactivate</button>'+'</div>'+'</div>'+
(perks.length?'<ul style="margin:8px 0 0 18px;padding:0;font-size:12px;color:#bbb;line-height:1.7">'+
perks.map(function(p){return'<li>'+(p||'').replace(/</g,'&lt;')+'</li>';}).join('')+'</ul>':'')+'</div>';}).join('');}
function newPartnerTier(){['ptEditId','ptName','ptTagline','ptDescription','ptPerks','ptCta'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('ptPrice').value=0;document.getElementById('ptSort').value=100;document.getElementById('ptFeatured').checked=false;document.getElementById('ptActive').checked=true;document.getElementById('partnerTierFormWrap').style.display='block';document.getElementById('ptName').focus();}
function editPartnerTier(e,btn){var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];var t=PARTNERS_TIERS_CACHE.find(function(x){return x.id===id;});if(!t)return;document.getElementById('ptEditId').value=t.id;document.getElementById('ptName').value=t.name||'';document.getElementById('ptTagline').value=t.tagline||'';document.getElementById('ptDescription').value=t.description||'';document.getElementById('ptPrice').value=t.monthly_price_cents||0;document.getElementById('ptSort').value=t.sort_order||100;var perks=Array.isArray(t.perks)?t.perks:(typeof t.perks==='string'?(function(){try{return JSON.parse(t.perks);}catch(e){return[];}})():[]);document.getElementById('ptPerks').value=perks.join('\n');document.getElementById('ptCta').value=t.cta_label||'';document.getElementById('ptFeatured').checked=!!t.is_featured;document.getElementById('ptActive').checked=!!t.is_active;document.getElementById('partnerTierFormWrap').style.display='block';}
function cancelPartnerTierForm(){document.getElementById('partnerTierFormWrap').style.display='none';}
function savePartnerTier(){var id=document.getElementById('ptEditId').value;var perksRaw=document.getElementById('ptPerks').value||'';var perks=perksRaw.split(/\r?\n/).map(function(s){return s.trim();}).filter(Boolean);var body={name:(document.getElementById('ptName').value||'').trim(),tagline:(document.getElementById('ptTagline').value||'').trim()||null,description:(document.getElementById('ptDescription').value||'').trim()||null,monthly_price_cents:parseInt(document.getElementById('ptPrice').value,10)||0,perks:perks,sort_order:parseInt(document.getElementById('ptSort').value,10)||100,cta_label:(document.getElementById('ptCta').value||'').trim()||null,is_featured:document.getElementById('ptFeatured').checked,is_active:document.getElementById('ptActive').checked,};if(!body.name){showToast('Name required',true);return;}
var url=id?(ATP_API+'/partners/admin/tiers/'+id):(ATP_API+'/partners/admin/tiers');fetch(url,{method:id?'PATCH':'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(id?'✅ Tier updated':'✅ Tier created');cancelPartnerTierForm();loadPartnerTiers();});}
function deletePartnerTier(e,btn){if(!confirm('Deactivate this tier? It will hide from the /partners page; existing inquiries that reference it keep their tier name.'))return;var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];fetch(ATP_API+'/partners/admin/tiers/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Tier deactivated');loadPartnerTiers();});}
var PARTNERS_DIR_CACHE=[];function loadPartnerDirectory(){fetch(ATP_API+'/partners/admin/directory',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){PARTNERS_DIR_CACHE=(data&&data.partners)||[];renderPartnerDirectory(PARTNERS_DIR_CACHE);});}
function _populatePartnerDirTierSelect(){var sel=document.getElementById('pdTier');if(!sel)return;sel.innerHTML='<option value="">No tier</option>'+
PARTNERS_TIERS_CACHE.map(function(t){return'<option value="'+t.id+'">'+(t.name||'').replace(/</g,'&lt;')+'</option>';}).join('');}
function renderPartnerDirectory(list){var el=document.getElementById('partnerDirectoryList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center">No partners in the directory yet. Add one above to populate the logo strip on /partners.</div>';return;}
el.innerHTML='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px">'+
list.map(function(p){var status=p.is_active?'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(168,255,0,.15);color:#A8FF00">Active</span>':'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(255,255,255,.06);color:#666">Off</span>';var name=(p.name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var logoBlock=p.logo_url?'<img loading="lazy" src="'+p.logo_url.replace(/"/g,'&quot;')+'" alt="" style="max-height:40px;max-width:100%;object-fit:contain;margin-bottom:8px;filter:brightness(1.3)">':'<div style="font-family:var(--ff-display, Barlow Condensed);font-size:18px;font-weight:800;color:#888;margin-bottom:8px">'+name+'</div>';return'<div style="background:#0d0d0d;border:1px solid #222;border-radius:10px;padding:16px">'+
logoBlock+'<div style="display:flex;justify-content:space-between;align-items:center;gap:8px;margin-bottom:6px">'+'<span style="font-size:14px;font-weight:700;color:#fff">'+name+'</span>'+
status+'</div>'+
(p.tier_name?'<div style="font-size:11px;color:#A8FF00;margin-bottom:6px">'+p.tier_name+'</div>':'')+
(p.testimonial?'<div style="font-size:11px;color:#888;font-style:italic;margin-bottom:8px;line-height:1.5">"'+(p.testimonial||'').slice(0,80).replace(/</g,'&lt;')+(p.testimonial.length>80?'…':'')+'"</div>':'')+'<div style="display:flex;gap:6px">'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px;flex:1" data-atp-call="editPartnerDirectory" data-args=\'["'+p.id+'"]\'>Edit</button>'+'<button class="admin-btn admin-btn-danger" style="font-size:11px;padding:5px 10px" data-atp-call="deletePartnerDirectory" data-args=\'["'+p.id+'"]\'>×</button>'+'</div>'+'</div>';}).join('')+'</div>';}
function newPartnerDirectory(){['pdEditId','pdName','pdLogo','pdWebsite','pdBlurb','pdQuote','pdQuoteAttr'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('pdSort').value=100;document.getElementById('pdTier').value='';document.getElementById('pdFeatured').checked=false;document.getElementById('pdActive').checked=true;_populatePartnerDirTierSelect();document.getElementById('partnerDirFormWrap').style.display='block';document.getElementById('pdName').focus();}
function editPartnerDirectory(e,btn){var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];var p=PARTNERS_DIR_CACHE.find(function(x){return x.id===id;});if(!p)return;document.getElementById('pdEditId').value=p.id;document.getElementById('pdName').value=p.name||'';document.getElementById('pdLogo').value=p.logo_url||'';document.getElementById('pdWebsite').value=p.website_url||'';document.getElementById('pdBlurb').value=p.blurb||'';document.getElementById('pdQuote').value=p.testimonial||'';document.getElementById('pdQuoteAttr').value=p.testimonial_attribution||'';document.getElementById('pdSort').value=p.sort_order||100;document.getElementById('pdFeatured').checked=!!p.is_featured;document.getElementById('pdActive').checked=!!p.is_active;_populatePartnerDirTierSelect();if(p.tier_id)document.getElementById('pdTier').value=p.tier_id;document.getElementById('partnerDirFormWrap').style.display='block';}
function cancelPartnerDirectoryForm(){document.getElementById('partnerDirFormWrap').style.display='none';}
function savePartnerDirectory(){var id=document.getElementById('pdEditId').value;var body={name:(document.getElementById('pdName').value||'').trim(),logo_url:(document.getElementById('pdLogo').value||'').trim()||null,website_url:(document.getElementById('pdWebsite').value||'').trim()||null,tier_id:document.getElementById('pdTier').value||null,blurb:(document.getElementById('pdBlurb').value||'').trim()||null,testimonial:(document.getElementById('pdQuote').value||'').trim()||null,testimonial_attribution:(document.getElementById('pdQuoteAttr').value||'').trim()||null,sort_order:parseInt(document.getElementById('pdSort').value,10)||100,is_featured:document.getElementById('pdFeatured').checked,is_active:document.getElementById('pdActive').checked,};if(!body.name){showToast('Name required',true);return;}
var url=id?(ATP_API+'/partners/admin/directory/'+id):(ATP_API+'/partners/admin/directory');fetch(url,{method:id?'PATCH':'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(id?'✅ Partner updated':'✅ Partner added');cancelPartnerDirectoryForm();loadPartnerDirectory();});}
function deletePartnerDirectory(e,btn){if(!confirm('Remove this partner from the directory? Their logo will disappear from /partners immediately.'))return;var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];fetch(ATP_API+'/partners/admin/directory/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Partner removed');loadPartnerDirectory();});}
var PARTNERS_OFFERS_CACHE=[];var PARTNERS_DIR_CACHE=[];function loadPartnerOffers(){fetch(ATP_API+'/offers/admin/offers',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){PARTNERS_OFFERS_CACHE=(data&&data.offers)||[];renderPartnerOffers(PARTNERS_OFFERS_CACHE);}).catch(function(){document.getElementById('partnerOffersList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load offers.</div>';});fetch(ATP_API+'/partners/admin/directory',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(d){PARTNERS_DIR_CACHE=(d&&d.directory)||[];_populatePartnerOfferDropdown();}).catch(function(){});}
function renderPartnerOffers(list){var el=document.getElementById('partnerOffersList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center;font-size:13px">No offers yet. Hit "+ New offer" to publish the first member perk.</div>';return;}
el.innerHTML=list.map(function(o){var typeColor=o.offer_type==='event'?'#f5c042':(o.offer_type==='promo'?'#ff8a3d':'#A8FF00');var typeLabel=o.offer_type==='event'?'EVENT':(o.offer_type==='promo'?'PROMO':'DISCOUNT');var partner=o.partner_name?'<div style="font-size:11px;color:#aaa;margin-bottom:4px">'+_escAttr(o.partner_name)+'</div>':'';var status=o.is_active?'Active':'Hidden';var statusColor=o.is_active?'#A8FF00':'#666';return('<div style="display:grid;grid-template-columns:1fr auto;gap:14px;align-items:center;padding:14px;background:#0f0f0f;border:1px solid #1e1e1e;border-radius:8px;margin-bottom:10px">'+'<div>'+
partner+'<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">'+'<span style="font-size:9px;font-weight:800;letter-spacing:.1em;background:'+typeColor+';color:#0a0a0a;padding:2px 7px;border-radius:4px">'+typeLabel+'</span>'+
(o.is_featured?'<span style="font-size:9px;font-weight:800;letter-spacing:.1em;background:#fff;color:#0a0a0a;padding:2px 7px;border-radius:4px">★ FEATURED</span>':'')+'<span style="font-size:10px;color:'+statusColor+'">'+status+'</span>'+'</div>'+'<div style="font-size:14px;color:#fff;font-weight:600">'+_escAttr(o.title)+'</div>'+'<div style="font-size:11px;color:#777;margin-top:4px">'+
(o.discount_pct?o.discount_pct+'% off · ':'')+
(o.points_required>0?o.points_required+' pts · ':'Free · ')+
(o.ends_at?'Ends '+new Date(o.ends_at).toLocaleDateString():'No expiry')+'</div>'+'</div>'+'<div style="display:flex;gap:6px">'+'<button class="admin-btn" data-atp-call="editPartnerOffer" data-args=\'["'+o.id+'"]\' style="font-size:11px;padding:6px 10px">Edit</button>'+'<button class="admin-btn" data-atp-call="deletePartnerOffer" data-args=\'["'+o.id+'"]\' style="font-size:11px;padding:6px 10px;color:#f87171">Delete</button>'+'</div>'+'</div>');}).join('');}
function _populatePartnerOfferDropdown(){var sel=document.getElementById('poPartner');if(!sel)return;var cur=sel.value;sel.innerHTML='<option value="">— No partner / ATP direct —</option>'+
PARTNERS_DIR_CACHE.map(function(p){return'<option value="'+p.id+'">'+_escAttr(p.name)+'</option>';}).join('');if(cur)sel.value=cur;}
function newPartnerOffer(){document.getElementById('partnerOfferFormWrap').style.display='';document.getElementById('poEditId').value='';['poTitle','poDescription','poImage','poExternalUrl','poEventLocation','poTerms','poEventDate','poStartsAt','poEndsAt'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('poType').value='discount';document.getElementById('poDiscount').value='';document.getElementById('poPoints').value=0;document.getElementById('poEventPrice').value='';document.getElementById('poSort').value=100;document.getElementById('poPartner').value='';document.getElementById('poFeatured').checked=false;document.getElementById('poActive').checked=true;window.scrollTo({top:document.getElementById('partnerOfferFormWrap').offsetTop-80,behavior:'smooth'});}
function editPartnerOffer(e,btn){var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];var o=PARTNERS_OFFERS_CACHE.find(function(x){return x.id===id;});if(!o)return;document.getElementById('partnerOfferFormWrap').style.display='';document.getElementById('poEditId').value=o.id;document.getElementById('poTitle').value=o.title||'';document.getElementById('poType').value=o.offer_type||'discount';document.getElementById('poSort').value=o.sort_order||100;document.getElementById('poPartner').value=o.partner_id||'';document.getElementById('poDiscount').value=o.discount_pct!=null?o.discount_pct:'';document.getElementById('poPoints').value=o.points_required||0;document.getElementById('poDescription').value=o.description||'';document.getElementById('poImage').value=o.image_url||'';document.getElementById('poExternalUrl').value=o.external_url||'';document.getElementById('poEventDate').value=o.event_date?new Date(o.event_date).toISOString().slice(0,16):'';document.getElementById('poEventLocation').value=o.event_location||'';document.getElementById('poEventPrice').value=o.event_price_aed||'';document.getElementById('poStartsAt').value=o.starts_at?new Date(o.starts_at).toISOString().slice(0,16):'';document.getElementById('poEndsAt').value=o.ends_at?new Date(o.ends_at).toISOString().slice(0,16):'';document.getElementById('poTerms').value=o.terms||'';document.getElementById('poFeatured').checked=!!o.is_featured;document.getElementById('poActive').checked=o.is_active!==false;window.scrollTo({top:document.getElementById('partnerOfferFormWrap').offsetTop-80,behavior:'smooth'});}
function cancelPartnerOfferForm(){document.getElementById('partnerOfferFormWrap').style.display='none';}
function savePartnerOffer(){var id=document.getElementById('poEditId').value;var body={title:document.getElementById('poTitle').value.trim(),offer_type:document.getElementById('poType').value,partner_id:document.getElementById('poPartner').value||null,discount_pct:document.getElementById('poDiscount').value||null,points_required:parseInt(document.getElementById('poPoints').value,10)||0,description:document.getElementById('poDescription').value.trim()||null,image_url:document.getElementById('poImage').value.trim()||null,external_url:document.getElementById('poExternalUrl').value.trim()||null,event_date:document.getElementById('poEventDate').value||null,event_location:document.getElementById('poEventLocation').value.trim()||null,event_price_aed:document.getElementById('poEventPrice').value||null,starts_at:document.getElementById('poStartsAt').value||null,ends_at:document.getElementById('poEndsAt').value||null,terms:document.getElementById('poTerms').value.trim()||null,sort_order:parseInt(document.getElementById('poSort').value,10)||100,is_featured:document.getElementById('poFeatured').checked,is_active:document.getElementById('poActive').checked,};if(!body.title){showToast('❌ Title is required',true);return;}
var url=id?(ATP_API+'/offers/admin/offers/'+id):(ATP_API+'/offers/admin/offers');fetch(url,{method:id?'PATCH':'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Offer saved');cancelPartnerOfferForm();loadPartnerOffers();}).catch(function(){showToast('❌ Save failed',true);});}
function deletePartnerOffer(e,btn){if(!confirm('Delete this offer? Already-issued codes stay valid but no new ones can be generated.'))return;var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];fetch(ATP_API+'/offers/admin/offers/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Offer removed');loadPartnerOffers();});}
function loadPartnerRedemptions(){fetch(ATP_API+'/offers/admin/redemptions',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){renderPartnerRedemptions((data&&data.redemptions)||[]);}).catch(function(){document.getElementById('partnerRedemptionsList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load redemptions.</div>';});}
function renderPartnerRedemptions(list){var el=document.getElementById('partnerRedemptionsList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center;font-size:13px">No redemptions yet. Once a member generates a code, the audit log shows up here.</div>';return;}
el.innerHTML='<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">'+'<thead><tr style="text-align:left;color:#888;border-bottom:1px solid #2a2a2a">'+'<th style="padding:8px 10px">Member</th>'+'<th style="padding:8px 10px">Offer</th>'+'<th style="padding:8px 10px">Partner</th>'+'<th style="padding:8px 10px">Code</th>'+'<th style="padding:8px 10px">Points</th>'+'<th style="padding:8px 10px">Issued</th>'+'<th style="padding:8px 10px">Status</th>'+'</tr></thead><tbody>'+
list.map(function(r){var statusColor=r.status==='used'?'#aaa':(r.status==='expired'?'#ef4444':'#A8FF00');var statusBg=r.status==='used'?'rgba(255,255,255,.06)':(r.status==='expired'?'rgba(239,68,68,.14)':'rgba(168,255,0,.14)');return('<tr style="border-bottom:1px solid #1a1a1a">'+'<td style="padding:10px;color:#fff">'+_escAttr((r.first_name||'')+' '+(r.last_name||''))+'<div style="font-size:10px;color:#666">'+_escAttr(r.email||'')+'</div></td>'+'<td style="padding:10px;color:#ccc">'+_escAttr(r.offer_title||'')+'</td>'+'<td style="padding:10px;color:#888">'+_escAttr(r.partner_name||'—')+'</td>'+'<td style="padding:10px;color:#A8FF00;font-family:monospace;font-size:11px">'+_escAttr(r.code)+'</td>'+'<td style="padding:10px;color:#fff;text-align:center">'+(r.points_spent||0)+'</td>'+'<td style="padding:10px;color:#888">'+new Date(r.issued_at).toLocaleDateString()+'</td>'+'<td style="padding:10px">'+'<select onchange="updateRedemptionStatus(\''+r.id+'\', this.value)" style="background:'+statusBg+';color:'+statusColor+';border:1px solid '+statusColor+';padding:4px 6px;border-radius:4px;font-size:11px;font-weight:600">'+'<option value="issued"'+(r.status==='issued'?' selected':'')+'>Issued</option>'+'<option value="used"'+(r.status==='used'?' selected':'')+'>Used</option>'+'<option value="expired"'+(r.status==='expired'?' selected':'')+'>Expired</option>'+'</select>'+'</td>'+'</tr>');}).join('')+'</tbody></table></div>';}
function updateRedemptionStatus(id,status){fetch(ATP_API+'/offers/admin/redemptions/'+id,{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify({status:status}),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Status updated');});}
function _escAttr(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}